mapper.select:
select id, model_name as modelName, api_url as apiUrl, api_key as apiKey, temperature, max_tokens as maxTokens, status, creator_id as creatorId, creator_role as creatorRole, manager_id as managerId, create_time as createTime from model_config
and model_name like concat('%', #{modelName}, '%')
and status = #{status}
and creator_id = #{currentUserId} and creator_role = #{currentUserRole}
order by id desc

select id, model_name as modelName, api_url as apiUrl, api_key as apiKey, temperature, max_tokens as maxTokens, status, creator_id as creatorId, creator_role as creatorRole, manager_id as managerId, create_time as createTime from model_config
and status = '启用' and creator_id = #{currentUserId} and creator_role = #{currentUserRole}
order by id desc
